INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "アヤネ", "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 401, "2030/12/17 14:59:59", 24, 0.0, 2, 24001, 102301, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "アヤネ", "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 402, "2030/12/17 14:59:59", 24, 2.21, 2, 24002, 102301, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "アヤネ", "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 403, "2030/12/17 14:59:59", 24, 0.0, 2, 24003, 102301, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "アサヒ", "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 701, "2030/12/17 14:59:59", 24, 1.99, 1, 24004, 192201, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "アサヒ", "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 702, "2030/12/17 14:59:59", 24, 2.21, 2, 24005, 192201, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "アサヒ", "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 703, "2030/12/17 14:59:59", 24, 3.33, 1, 24006, 192201, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "部員３", "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 801, "2030/12/17 14:59:59", 24, 0.0, 2, 24007, 192301, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "部員３", "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 802, "2030/12/17 14:59:59", 24, 2.68, 2, 24008, 192301, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "部員３", "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 803, "2030/12/17 14:59:59", 24, 0.0, 2, 24009, 192301, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "", "やった！", 501, "2030/12/17 14:59:59", 24, 0.0, 1, 24010, 192501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "", "勝ったよ！", 502, "2030/12/17 14:59:59", 24, 0.0, 1, 24011, 192501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "", "いい調子！", 503, "2030/12/17 14:59:59", 24, 0.0, 1, 24012, 192501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 6, 0.0, "ミサト", "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 111, "2030/12/17 14:59:59", 24, 5.33, 2, 24013, 113501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "ミサト", "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 112, "2030/12/17 14:59:59", 24, 6.85, 2, 24014, 113501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "ミサト", "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 113, "2030/12/17 14:59:59", 24, 3.0, 2, 24015, 113501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "ダイチ", "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 611, "2030/12/17 14:59:59", 24, 6.11, 2, 24016, 192401, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "ダイチ", "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 612, "2030/12/17 14:59:59", 24, 6.75, 2, 24017, 192401, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "ダイチ", "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 613, "2030/12/17 14:59:59", 24, 0.0, 2, 24018, 192401, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "ハツネ", "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 211, "2030/12/17 14:59:59", 24, 4.52, 1, 24019, 113401, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "ハツネ", "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 212, "2030/12/17 14:59:59", 24, 3.89, 1, 24020, 113401, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "ハツネ", "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 213, "2030/12/17 14:59:59", 24, 13.49, 2, 24021, 113401, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "カヤ", "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 311, "2030/12/17 14:59:59", 24, 3.17, 2, 24022, 106501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "カヤ", "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 312, "2030/12/17 14:59:59", 24, 4.42, 2, 24023, 106501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 6, 0.0, "カヤ", "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 313, "2030/12/17 14:59:59", 24, 2.89, 1, 24024, 106501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 4, 0.0, "アヤネ", "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 421, "2030/12/17 14:59:59", 24, 3.71, 3, 24025, 102301, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "アサヒ", "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 721, "2030/12/17 14:59:59", 24, 5.1, 1, 24026, 192201, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "部員３", "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 821, "2030/12/17 14:59:59", 24, 4.34, 3, 24027, 192301, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "", "いい勝負だったよ\nまたやろうね", 521, "2030/12/17 14:59:59", 24, 0.0, 1, 24028, 192501, 0.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "ミサト", "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 101, "2030/12/17 14:59:59", 24, 5.62, 2, 24029, 113501, -360.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "ミサト", "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 102, "2030/12/17 14:59:59", 24, 9.58, 2, 24030, 113501, -360.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "ミサト", "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 103, "2030/12/17 14:59:59", 24, 0.0, 2, 24031, 113501, -360.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 2, 0.0, "ミサト", "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 104, "2030/12/17 14:59:59", 24, 9.13, 1, 24032, 113501, -360.0, 10046);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES ("2020/07/31 12:00:00", 1, 0.0, "ミサト", "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 105, "2030/12/17 14:59:59", 24, 8.27, 2, 24033, 113501, -360.0, 10046);
